  Optional<ProductEntity> findByName(String name);
}

package com.aes.product.infrastructure.persistence;

import com.aes.product.domain.entity.Product;

public class ProductMapper {

  public static ProductEntity toEntity(Product product) {
    return new ProductEntity(product.getId(), product.getName(), product.getPrice());
  }
}

public static Product toDomain(ProductEntity entity) {
  return new Product(entity.getId(), entity.getName(), entity.getPrice());
}

package com.aes.product.infrastructure.persistence;

import com.aes.product.domain.entity.Product;
import com.aes.product.domain.port.ProductRepositoryPort;

public class ProductRepositoryAdapter implements ProductRepositoryPort {

  private final JpaProductRepository jpaProductRepository;

  public ProductRepositoryAdapter(JpaProductRepository jpaProductRepository) {
    this.jpaProductRepository = jpaProductRepository;
  }
}

@Override
public java.util.Optional<Product> findByName(String name) {
  return jpaProductRepository.findByName(name).map(ProductMapper::toDomain);
}

@Override
public Product save(Product product) {
  ProductEntity entity = ProductMapper.toEntity(product);
  ProductEntity savedEntity = jpaProductRepository.save(entity);
  return ProductMapper.toDomain(savedEntity);
}

@Override
public java.util.List<Product> findAll() {
  return jpaProductRepository.findAll()
      .stream()
      .map(ProductMapper::toDomain)
      .collect(java.util.stream.Collectors.toList());
}

package com.aes.product.infrastructure.config;

import com.aes.product.application.usecase.CreateProductUseCase;
