import com.aes.product.infrastructure.persistence.JpaProductRepository;
import com.aes.product.infrastructure.persistence.ProductRepositoryAdapter;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class BeanConfiguration {
}

@Bean
public ProductRepositoryPort productRepositoryPort(JpaProductRepository jpaProductRepository) {
  return new ProductRepositoryAdapter(jpaProductRepository);
}

@Bean
public CreateProductUseCase createProductUseCase(ProductRepositoryPort productRepositoryPort) {
  return new CreateProductUseCase(productRepositoryPort);
}

@Bean
public ListProductsUseCase listProductsUseCase(ProductRepositoryPort productRepositoryPort) {
  return new ListProductsUseCase(productRepositoryPort);
}

package com.aes.product.infrastructure.controller;

import com.aes.product.application.usecase.CreateProductUseCase;
import com.aes.product.application.usecase.ListProductsUseCase;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/products")
public class ProductController {

  private final CreateProductUseCase createProductUseCase;
  private final ListProductsUseCase listProductsUseCase;

  public ProductController(CreateProductUseCase createProductUseCase,
                            ListProductsUseCase listProductsUseCase) {
    this.createProductUseCase = createProductUseCase;
    this.listProductsUseCase = listProductsUseCase;
  }
}

@org.springframework.web.bind.annotation.PostMapping
public org.springframework.http.ResponseEntity<?> create(
    @org.springframework.web.bind.annotation.RequestBody
    com.aes.product.application.dto.CreateProductRequest request) {
  try {
    var response = createProductUseCase.execute(request);
    return org.springframework.http.ResponseEntity.ok(response);
  } catch (IllegalArgumentException err) {
    return org.springframework.http.ResponseEntity.badRequest().body(err.getMessage());
  }
}

@org.springframework.web.bind.annotation.GetMapping
public org.springframework.http.ResponseEntity<?> list() {
  return org.springframework.http.ResponseEntity.ok(listProductsUseCase.execute());
}

